   282→        <span class="hero-meta-label">Team size</span>
   283→        <span class="hero-meta-value">2-3 people</span>
   284→      </div>
   285→      <div class="hero-meta-item">
   286→        <span class="hero-meta-label">Backed by</span>
   287→        <span class="hero-meta-value">VC + YC founders</span>
   288→      </div>
   289→      <div class="hero-meta-item">
   290→        <span class="hero-meta-label">Output</span>
   291→        <span class="hero-meta-value">Working demo</span>
   292→      </div>
