   FAQ SECTION
   ============================================ */
.faq-section {
  padding: 120px 0;
  background: #ffffff;
  border-top: 1px solid rgba(28,27,26,0.06);
}

.faq-container {
  max-width: 760px;
  margin: 0 auto;
}

.faq-category {
  font-family: var(--font-display);
  font-size: 13px;
  color: var(--blue);
  text-transform: uppercase;
  letter-spacing: 2px;
  margin: 60px 0 24px 0;
  font-weight: 600;
}

.faq-category:first-of-type {
  margin-top: 0;
}

.faq-item {
  border-bottom: 1px solid rgba(28,27,26,0.08); /* slight border */
}

/* Use standard HTML details for simplest clean implementation */
.faq-item details {
  width: 100%;
}

.faq-item summary {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 24px 0;
  font-size: 18px;
  font-weight: 500;
  letter-spacing: -0.3px;
  color: var(--dark);
  cursor: pointer;
  list-style: none; /* removes default arrow in most modern browsers */
}

.faq-item summary::-webkit-details-marker {
  display: none;
}

.faq-item summary::after {
  content: '+';
  font-size: 28px;
  font-weight: 300;
  color: var(--gray);
  transition: transform 0.3s ease;
}

.faq-item details[open] summary::after {
  transform: rotate(45deg); /* Turns the neat plus into a cross */
}

.faq-item .faq-answer {
  padding-bottom: 32px;
  font-size: 16px;
  color: var(--gray);
  line-height: 1.6;
}

/* ============================================
   LOGOS
   ============================================ */
.logos-section {
  padding: 80px 0;
  text-align: center;
}

